// SPDX-License-Identifier: MIT
pragma solidity ^0.8.24;

import "@openzeppelin/contracts/token/ERC20/ERC20.sol";
import "@openzeppelin/contracts/token/ERC20/extensions/ERC20Burnable.sol";
import "@openzeppelin/contracts/access/AccessControl.sol";

contract OAIToken is ERC20, ERC20Burnable, AccessControl {
    bytes32 public constant MINTER_ROLE = keccak256("MINTER_ROLE");

    uint256 public constant MAX_SUPPLY = 1_000_000_000 ether;

    constructor() ERC20("OracleAI", "OAI") {
        _grantRole(DEFAULT_ADMIN_ROLE, msg.sender);
        _grantRole(MINTER_ROLE, msg.sender);
        _mint(msg.sender, MAX_SUPPLY);
    }

    function mintAirdrop(address to, uint256 amount) external onlyRole(MINTER_ROLE) {
        require(totalSupply() + amount <= MAX_SUPPLY, "Exceeds max supply");
        _mint(to, amount);
    }
}

contracts/Points.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.24;

import "@openzeppelin/contracts/access/AccessControl.sol";

contract Points is AccessControl {
    bytes32 public constant OPERATOR_ROLE = keccak256("OPERATOR_ROLE");

    struct UserPoints {
        uint256 points;
        uint256 weeklyPoints;
        uint256 streak;
        uint256 lastCheckIn;
        uint256 totalCheckIns;
        uint256 correctPredictions;
        uint256 totalPredictions;
    }

    mapping(address => UserPoints) public users;
    address[] public allUsers;
    mapping(address => bool) private _isUser;

    uint256 public totalPointsIssued;

    event PointsAdded(address indexed user, uint256 amount, uint256 total);
    event StreakUpdated(address indexed user, uint256 streak);
    event PredictionBonusAdded(address indexed user, uint256 bonus);

    constructor() {
        _grantRole(DEFAULT_ADMIN_ROLE, msg.sender);
    }

    function addPoints(address user, uint256 amount, uint256 streak) external onlyRole(OPERATOR_ROLE) {
        if (!_isUser[user]) {
            allUsers.push(user);
            _isUser[user] = true;
        }

        users[user].points += amount;
        users[user].weeklyPoints += amount;
        users[user].streak = streak;
        users[user].lastCheckIn = block.timestamp;
        users[user].totalCheckIns++;
        totalPointsIssued += amount;

        emit PointsAdded(user, amount, users[user].points);
        emit StreakUpdated(user, streak);
    }

    function addPredictionBonus(address user, uint256 bonus, bool correct) external onlyRole(OPERATOR_ROLE) {
        if (!_isUser[user]) {
            allUsers.push(user);
            _isUser[user] = true;
        }

        users[user].points += bonus;
        users[user].weeklyPoints += bonus;
        users[user].totalPredictions++;
        if (correct) users[user].correctPredictions++;
        totalPointsIssued += bonus;

        emit PredictionBonusAdded(user, bonus);
    }

    function resetWeeklyPoints(address[] calldata addrs) external onlyRole(OPERATOR_ROLE) {
        for (uint i = 0; i < addrs.length; i++) {
            users[addrs[i]].weeklyPoints = 0;
        }
    }

    function getUserPoints(address user) external view returns (UserPoints memory) {
        return users[user];
    }

    function getUserCount() external view returns (uint256) {
        return allUsers.length;
    }

    function getTopUsers(uint256 count) external view returns (address[] memory, uint256[] memory) {
        uint256 len = allUsers.length < count ? allUsers.length : count;
        address[] memory topAddrs = new address[](len);
        uint256[] memory topPts = new uint256[](len);

        for (uint i = 0; i < allUsers.length; i++) {
            uint256 pts = users[allUsers[i]].weeklyPoints;
            for (uint j = 0; j < len; j++) {
                if (pts > topPts[j]) {
                    for (uint k = len - 1; k > j; k--) {
                        topAddrs[k] = topAddrs[k - 1];
                        topPts[k] = topPts[k - 1];
                    }
                    topAddrs[j] = allUsers[i];
                    topPts[j] = pts;
                    break;
                }
            }
        }
        return (topAddrs, topPts);
    }
}

contracts/Prediction.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.24;

import "@openzeppelin/contracts/access/AccessControl.sol";

interface IPoints {
    function addPredictionBonus(address user, uint256 bonus, bool correct) external;
}

contract Prediction is AccessControl {
    bytes32 public constant OPERATOR_ROLE = keccak256("OPERATOR_ROLE");

    enum Category { SPORTS, POLITICS, ECONOMY, CRYPTO, CLIMATE }

    struct PredictionEvent {
        uint256 id;
        string title;
        Category category;
        uint256 aiProbability; // 0-100
        uint256 deadline;
        bool resolved;
        bool outcome;
        uint256 totalVotesYes;
        uint256 totalVotesNo;
    }

    struct UserVote {
        bool voted;
        bool prediction;
    }

    IPoints public pointsContract;
    uint256 public eventCount;

    uint256 public constant CORRECT_BONUS = 50;
    uint256 public constant BEAT_AI_BONUS = 100;

    mapping(uint256 => PredictionEvent) public events;
    mapping(uint256 => mapping(address => UserVote)) public userVotes;
    mapping(uint256 => address[]) public eventVoters;

    event EventCreated(uint256 indexed id, string title, Category category, uint256 deadline);
    event VoteSubmitted(uint256 indexed eventId, address indexed user, bool prediction);
    event EventResolved(uint256 indexed id, bool outcome, uint256 winnersCount);

    constructor(address _points) {
        _grantRole(DEFAULT_ADMIN_ROLE, msg.sender);
        _grantRole(OPERATOR_ROLE, msg.sender);
        pointsContract = IPoints(_points);
    }

    function createEvent(
        string calldata title,
        Category category,
        uint256 deadline,
        uint256 aiProbability
    ) external onlyRole(OPERATOR_ROLE) returns (uint256) {
        require(deadline > block.timestamp, "Past deadline");
        require(aiProbability <= 100, "Invalid probability");

        eventCount++;
        events[eventCount] = PredictionEvent({
            id: eventCount,
            title: title,
            category: category,
            aiProbability: aiProbability,
            deadline: deadline,
            resolved: false,
            outcome: false,
            totalVotesYes: 0,
            totalVotesNo: 0
        });

        emit EventCreated(eventCount, title, category, deadline);
        return eventCount;
    }

    function submitPrediction(uint256 eventId, bool _prediction) external {
        PredictionEvent storage evt = events[eventId];
        require(evt.id != 0, "Event not found");
        require(!evt.resolved, "Already resolved");
        require(block.timestamp < evt.deadline, "Past deadline");
        require(!userVotes[eventId][msg.sender].voted, "Already voted");

        userVotes[eventId][msg.sender] = UserVote(true, _prediction);
        eventVoters[eventId].push(msg.sender);

        if (_prediction) evt.totalVotesYes++;
        else evt.totalVotesNo++;

        emit VoteSubmitted(eventId, msg.sender, _prediction);
    }

    function resolveEvent(uint256 eventId, bool actualOutcome) external onlyRole(OPERATOR_ROLE) {
        PredictionEvent storage evt = events[eventId];
        require(evt.id != 0, "Event not found");
        require(!evt.resolved, "Already resolved");

        evt.resolved = true;
        evt.outcome = actualOutcome;

        bool aiWasRight = (evt.aiProbability >= 50) == actualOutcome;
        uint256 winnersCount = 0;

        address[] memory voters = eventVoters[eventId];
        for (uint i = 0; i < voters.length; i++) {
            UserVote memory vote = userVotes[eventId][voters[i]];
            bool userCorrect = vote.prediction == actualOutcome;

            if (userCorrect) {
                winnersCount++;
                uint256 bonus = CORRECT_BONUS;
                if (!aiWasRight) bonus += BEAT_AI_BONUS;
                pointsContract.addPredictionBonus(voters[i], bonus, true);
            } else {
                pointsContract.addPredictionBonus(voters[i], 0, false);
            }
        }

        emit EventResolved(eventId, actualOutcome, winnersCount);
    }

    function getEvent(uint256 eventId) external view returns (PredictionEvent memory) {
        return events[eventId];
    }

    function getUserVote(uint256 eventId, address user) external view returns (UserVote memory) {
        return userVotes[eventId][user];
    }

    function getActiveEvents(uint256 limit) external view returns (PredictionEvent[] memory) {
        uint256 count = 0;
        for (uint i = eventCount; i > 0 && count < limit; i--) {
            if (!events[i].resolved && block.timestamp < events[i].deadline) count++;
        }

        PredictionEvent[] memory result = new PredictionEvent[](count);
        uint256 idx = 0;
        for (uint i = eventCount; i > 0 && idx < count; i--) {
            if (!events[i].resolved && block.timestamp < events[i].deadline) {
                result[idx++] = events[i];
            }
        }
        return result;
    }
}

contracts/PrizePool.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.24;

import "@openzeppelin/contracts/access/AccessControl.sol";
import "@openzeppelin/contracts/utils/ReentrancyGuard.sol";

contract PrizePool is AccessControl, ReentrancyGuard {
    bytes32 public constant DISTRIBUTOR_ROLE = keccak256("DISTRIBUTOR_ROLE");

    uint256 public totalDistributed;

    event PrizeReceived(uint256 amount);
    event PrizesDistributed(uint256 total, uint256 winnersCount);
    event EmergencyWithdraw(address to, uint256 amount);

    constructor() {
        _grantRole(DEFAULT_ADMIN_ROLE, msg.sender);
    }

    receive() external payable {
        emit PrizeReceived(msg.value);
    }

    function distributePrizes(
        address[] calldata winners,
        uint256[] calldata shares
    ) external onlyRole(DISTRIBUTOR_ROLE) nonReentrant {
        require(winners.length == shares.length, "Length mismatch");

        uint256 total = 0;
        for (uint i = 0; i < shares.length; i++) {
            total += shares[i];
        }
        require(total <= address(this).balance, "Insufficient balance");

        for (uint i = 0; i < winners.length; i++) {
            if (shares[i] > 0) {
                (bool ok, ) = winners[i].call{value: shares[i]}("");
                require(ok, "Transfer failed");
            }
        }
        totalDistributed += total;
        emit PrizesDistributed(total, winners.length);
    }

    function emergencyWithdraw(address to) external onlyRole(DEFAULT_ADMIN_ROLE) nonReentrant {
        uint256 bal = address(this).balance;
        (bool ok, ) = to.call{value: bal}("");
        require(ok, "Transfer failed");
        emit EmergencyWithdraw(to, bal);
    }

    function getBalance() external view returns (uint256) {
        return address(this).balance;
    }
}

contracts/Referral.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.24;

import "@openzeppelin/contracts/access/AccessControl.sol";
import "@openzeppelin/contracts/utils/ReentrancyGuard.sol";

contract Referral is AccessControl, ReentrancyGuard {
    bytes32 public constant OPERATOR_ROLE = keccak256("OPERATOR_ROLE");

    uint256 public constant MAX_LEVELS = 6;
    uint256 public constant MAX_DIRECT_REFERRALS = 100;

    // Percentages out of 1000 (10% = 100, 5% = 50, etc.)
    uint256[6] public levelPercents = [100, 50, 30, 20, 15, 10];

    mapping(address => address) public referrer;
    mapping(address => address[]) public directReferrals;
    mapping(address => bool) public hasReferrer;
    mapping(address => uint256) public totalEarnings;

    event ReferralRegistered(address indexed user, address indexed referrer);
    event ReferralPaid(address indexed referrer, address indexed from, uint256 level, uint256 amount);

    constructor() {
        _grantRole(DEFAULT_ADMIN_ROLE, msg.sender);
    }

    function registerReferral(address user, address ref) external onlyRole(OPERATOR_ROLE) {
        require(!hasReferrer[user], "Already has referrer");
        require(user != ref, "Self-referral");
        require(ref != address(0), "Zero referrer");
        require(directReferrals[ref].length < MAX_DIRECT_REFERRALS, "Max referrals reached");

        address current = ref;
        for (uint i = 0; i < MAX_LEVELS; i++) {
            require(current != user, "Circular ref");
            if (!hasReferrer[current]) break;
            current = referrer[current];
        }

        referrer[user] = ref;
        hasReferrer[user] = true;
        directReferrals[ref].push(user);

        emit ReferralRegistered(user, ref);
    }

    function distributeReferralFees(
        address user,
        uint256 totalReferralFee
    ) external payable onlyRole(OPERATOR_ROLE) nonReentrant {
        if (!hasReferrer[user]) return;

        address current = referrer[user];
        uint256 distributed = 0;

        for (uint256 level = 0; level < MAX_LEVELS && current != address(0); level++) {
            uint256 share = (totalReferralFee * levelPercents[level]) / 1000;
            if (share > 0 && distributed + share <= msg.value) {
                (bool ok, ) = current.call{value: share}("");
                if (ok) {
                    totalEarnings[current] += share;
                    distributed += share;
                    emit ReferralPaid(current, user, level + 1, share);
                }
            }
            if (!hasReferrer[current]) break;
            current = referrer[current];
        }

        // Return undistributed to sender
        if (distributed < msg.value) {
            (bool ok, ) = msg.sender.call{value: msg.value - distributed}("");
            require(ok, "Refund failed");
        }
    }

    function getDirectReferrals(address user) external view returns (address[] memory) {
        return directReferrals[user];
    }

    function getReferralChain(address user) external view returns (address[6] memory chain) {
        address current = user;
        for (uint i = 0; i < MAX_LEVELS; i++) {
            if (!hasReferrer[current]) break;
            current = referrer[current];
            chain[i] = current;
        }
    }
}

